if (!window.confirm('Add 1,000 credits to ' + ${matrix_user_id:doublequote} + '?')) { return; }
const params = new URLSearchParams({ user: ${matrix_user_id:doublequote}, credit: '1000' });
(async () => {
try {
  const r = await fetch(${realm_server:doublequote} + '_grafana-add-credit?' + params.toString(), { method: 'POST', headers: { 'Authorization': 'Bearer ' + ${grafana_secret:doublequote} } });
  if (r.ok) {
    context.grafana.notifySuccess(['Credit added', '+1,000 credits to ' + ${matrix_user_id:doublequote} + '']);
    if (typeof context.grafana.refresh === 'function') { context.grafana.refresh(); }
  } else {
    const txt = await r.text();
    context.grafana.notifyError(['Add credit failed', 'HTTP ' + r.status + ': ' + txt]);
  }
} catch (err) {
  context.grafana.notifyError(['Add credit failed', String(err)]);
}

})().catch(function (err) { console.error('operator action handler error:', err); });

