const amount = Number((context.panel.elements.find(function(e){return e.id==='custom_amount';})||{}).value || 0);
if (amount <= 0) {
  context.grafana.notifyWarning(['Invalid amount', 'Enter a positive credit amount before clicking.']);
  return;
}
if (!window.confirm('Add ' + amount.toLocaleString() + ' credits to ' + ${matrix_user_id:doublequote} + '?')) { return; }
const params = new URLSearchParams({ user: ${matrix_user_id:doublequote}, credit: String(amount) });
(async () => {
try {
  const r = await fetch(${realm_server:doublequote} + '_grafana-add-credit?' + params.toString(), { method: 'POST', headers: { 'Authorization': 'Bearer ' + ${grafana_secret:doublequote} } });
  if (r.ok) {
